// Add daysToExpiry to every row
const now = new Date();
return $input.all().map(item => {
  const expiry = new Date(item.json.expiry_date);
  const diff = Math.ceil((expiry - now) / (1000*60*60*24));
  return {
    json: {
      ...item.json,
      daysToExpiry: diff
    }
  };
});
